import React, { useState } from 'react';
import { LayoutDashboard, ShoppingBag, Package, Settings, LogOut, MessageSquareText, PieChart, Megaphone, Archive, FileSpreadsheet, Headphones, Wrench, Crown, Sparkles, X, PlusCircle, BookText, BookOpen, MessageSquarePlus, Newspaper, Globe } from 'lucide-react';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onLogout: () => void;
  isOpen: boolean;
  onClose: () => void;
  onOpenGuide: () => void;
  onOpenFeedback: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab, onLogout, isOpen, onClose }) => {
  const [hoveredItem, setHoveredItem] = useState<string | null>(null);

  const mainMenuItems = [
    { id: 'dashboard', label: 'Tổng quan', icon: LayoutDashboard },
    { id: 'reports', label: 'Báo cáo', icon: PieChart },
    { id: 'create-order', label: 'Đơn ngoài sàn', icon: PlusCircle },
    { id: 'orders', label: 'Đơn hàng', icon: Package, color: 'orange' },
    { id: 'products', label: 'Sản phẩm', icon: ShoppingBag },
    { id: 'ecommerce-products', label: 'Sản phẩm TMĐT', icon: Globe },
    { id: 'inventory', label: 'Kho hàng', icon: Archive },
    { id: 'marketing', label: 'Marketing', icon: Megaphone },
    { id: 'messages', label: 'Tin nhắn', icon: MessageSquareText, color: 'yellow' },
    { id: 'invoices', label: 'Sổ & Hóa Đơn', icon: BookText },
    { id: 'tax', label: 'Báo cáo Thuế', icon: FileSpreadsheet }, 
    { id: 'tax-service', label: 'Dịch vụ Thuế', icon: Headphones, color: 'green' },
    { id: 'tools', label: 'Công cụ', icon: Wrench },
    { id: 'integrations', label: 'Cấu hình', icon: Settings },
  ];

  const supportMenuItems = [
    { id: 'news', label: 'Tin tức', icon: Newspaper, featured: true },
    { id: 'guide', label: 'Hướng dẫn sử dụng', icon: BookOpen },
    { id: 'feedback', label: 'Góp ý tính năng', icon: MessageSquarePlus },
  ];

  const handleItemClick = (id: string) => {
    setActiveTab(id);
    onClose(); 
  };

  const getCustomStyles = (id: string, isActive: boolean) => {
    if (isActive) return 'bg-indigo-50 text-indigo-700 shadow-sm ring-1 ring-indigo-100 font-bold';
    return 'text-slate-600 hover:text-indigo-600 font-medium transition-colors'; 
  };

  const getIconColor = (id: string, isActive: boolean) => {
    if (isActive) return 'text-indigo-600';
    switch (id) {
      case 'orders': return 'text-orange-500 group-hover:text-orange-600';
      case 'messages': return 'text-amber-500 group-hover:text-amber-600';
      case 'tax-service': return 'text-emerald-500 group-hover:text-emerald-600';
      default: return 'text-slate-400 group-hover:text-slate-600';
    }
  };

  const renderMenuItem = (item: any) => {
    const Icon = item.icon;
    const isActive = activeTab === item.id;

    return (
      <div key={item.id} className="relative group">
        <button
          onClick={() => handleItemClick(item.id)}
          className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm transition-all duration-200 ${getCustomStyles(item.id, isActive)}`}
        >
          <Icon size={18} className={`transition-colors ${getIconColor(item.id, isActive)}`} />
          <span className={isActive ? '' : ''}>{item.label}</span>
          {item.featured && !isActive && <Sparkles size={12} className="ml-auto text-indigo-400 animate-pulse" />}
        </button>
      </div>
    );
  };

  return (
    <>
      {/* Mobile Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/50 z-40 lg:hidden backdrop-blur-sm transition-opacity"
          onClick={onClose}
        />
      )}

      {/* Sidebar Container */}
      <aside className={`
        fixed lg:static inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 
        flex flex-col h-screen shadow-xl lg:shadow-none transition-transform duration-300 ease-in-out
        ${isOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        {/* Brand Header */}
        <div className="h-16 flex items-center px-6 border-b border-slate-100 shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold shadow-md shadow-indigo-200">
              <span className="text-lg">O</span>
            </div>
            <h1 className="text-lg font-bold text-slate-800 tracking-tight">OmniSales</h1>
          </div>
          <button onClick={onClose} className="lg:hidden ml-auto text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 flex flex-col overflow-hidden py-4 px-3">
          <div className="flex-1 overflow-y-auto scrollbar-hide space-y-0.5">
            {mainMenuItems.map(renderMenuItem)}
          </div>

          <div className="mt-2 pt-2 border-t border-slate-100 space-y-0.5 shrink-0">
            {supportMenuItems.map(renderMenuItem)}
          </div>
        </nav>

        {/* Bottom Actions */}
        <div className="p-4 border-t border-slate-100 space-y-3 shrink-0 bg-slate-50/50">
          {/* Upgrade Card */}
          <div className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-xl p-4 text-white shadow-lg shadow-indigo-200 relative overflow-hidden group cursor-pointer transition-transform hover:-translate-y-1" onClick={() => handleItemClick('membership')}>
              <div className="absolute top-0 right-0 w-20 h-20 bg-white/10 rounded-full blur-2xl -mr-10 -mt-10 pointer-events-none"></div>

              <div className="flex items-center gap-3 mb-3 relative z-10">
                <div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-sm shadow-inner">
                  <Crown size={16} className="text-yellow-300 fill-yellow-300" />
                </div>
                <div>
                  <h4 className="font-bold text-xs">Nâng cấp Pro</h4>
                  <p className="text-[10px] text-indigo-100 opacity-90">Mở khóa tính năng</p>
                </div>
              </div>

              <div className="w-full py-2 bg-white text-indigo-700 text-xs font-bold rounded-lg shadow-sm flex items-center justify-center gap-2 relative z-10 hover:bg-indigo-50 transition-colors">
                Nâng cấp ngay
              </div>
          </div>

          <button 
            onClick={onLogout}
            className="w-full flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-lg text-sm transition-colors group justify-center"
          >
            <LogOut size={16} className="group-hover:-translate-x-1 transition-transform" />
            Đăng xuất
          </button>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;

import React, { useState, useEffect, useMemo } from 'react';
import { MOCK_PRODUCTS, MOCK_ORDERS } from '../services/mockData';
import { Product, Order } from '../types';
import { 
  User, Phone, MapPin, Search, Trash2, Truck, 
  CreditCard, Package, CheckCircle, ChevronRight, UserPlus, PlusCircle,
  Box, Scale, History, DollarSign, Percent, ArrowLeft, Tag, Clock, Zap,
  FileSpreadsheet, Filter, Download, Calendar, MoreHorizontal, Printer, X
} from 'lucide-react';

const CARRIERS = [
  { id: 'ghtk', name: 'Giao Hàng Tiết Kiệm', logo: 'https://picsum.photos/50/50?random=ghtk', fee: 35000, time: 3, timeStr: '2-3 ngày' },
  { id: 'ghn', name: 'Giao Hàng Nhanh', logo: 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e3/Logo_GHN_Slogan_En.png/320px-Logo_GHN_Slogan_En.png', fee: 32000, time: 3, timeStr: '2-3 ngày' },
  { id: 'viettel', name: 'Viettel Post', logo: 'https://upload.wikimedia.org/wikipedia/commons/0/08/Viettel_Post_logo.png', fee: 28000, time: 4, timeStr: '3-4 ngày' },
];

const CreateOrder: React.FC = () => {
  const [viewMode, setViewMode] = useState<'list' | 'create'>('list');

  // Create Order State
  const [currentStep, setCurrentStep] = useState(1);
  const [customer, setCustomer] = useState({ name: '', phone: '', address: '', city: '', district: '', note: '' });
  const [selectedProducts, setSelectedProducts] = useState<{product: Product, quantity: number, price: number}[]>([]);
  const [productSearch, setProductSearch] = useState('');
  const [isProductDropdownOpen, setIsProductDropdownOpen] = useState(false);
  const [packageInfo, setPackageInfo] = useState({ weight: 500, length: 10, width: 10, height: 5 });
  const [selectedCarrierId, setSelectedCarrierId] = useState<string>('');
  const [shippingFee, setShippingFee] = useState(0);
  const [isCodEnabled, setIsCodEnabled] = useState(true);
  const [discountValue, setDiscountValue] = useState(0);
  const [discountType, setDiscountType] = useState<'fixed' | 'percent'>('fixed');

  // List / Management State
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [exportType, setExportType] = useState<'date' | 'month' | 'year'>('month');
  const [exportDate, setExportDate] = useState(new Date().toISOString().split('T')[0]);
  const [exportMonth, setExportMonth] = useState(new Date().toISOString().slice(0, 7)); // YYYY-MM
  const [exportYear, setExportYear] = useState(new Date().getFullYear());

  useEffect(() => {
    // Initialize with manual orders from mock + any local additions
    const manualOrders = MOCK_ORDERS.filter(o => o.platform === 'Manual');
    setOrders(manualOrders);
  }, []);

  const subtotal = selectedProducts.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const discountAmount = discountType === 'fixed' ? discountValue : (subtotal * discountValue) / 100;
  const totalAmount = Math.max(0, subtotal + shippingFee - discountAmount);

  // --- Handlers ---

  const handleAddProduct = (product: Product) => {
    setSelectedProducts(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { product, quantity: 1, price: product.price }];
    });
    setProductSearch('');
    setIsProductDropdownOpen(false);
  };

  const updateQuantity = (id: string, delta: number) => {
    setSelectedProducts(prev => prev.map(item => item.product.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item));
  };

  const handleCreateOrder = () => {
    if (!customer.name || !customer.phone || selectedProducts.length === 0 || !selectedCarrierId) return alert("Vui lòng điền đầy đủ thông tin.");

    const newOrder: any = {
      id: `MAN-${Date.now().toString().slice(-6)}`,
      customerName: customer.name,
      customerPhone: customer.phone,
      date: new Date().toLocaleString('vi-VN'),
      total: totalAmount,
      status: 'pending',
      items: selectedProducts.map(p => ({...p.product, quantity: p.quantity})),
      platform: 'Manual',
      shippingFee: shippingFee,
      isCOD: isCodEnabled,
      note: customer.note
    };

    setOrders([newOrder, ...orders]);
    setCustomer({ name: '', phone: '', address: '', city: '', district: '', note: '' });
    setSelectedProducts([]);
    setCurrentStep(1);
    setDiscountValue(0);
    setViewMode('list');
    alert("Tạo đơn hàng thành công!");
  };

  const handleExport = () => {
    let filename = '';
    if (exportType === 'date') filename = `Bao_cao_don_ngay_${exportDate}`;
    if (exportType === 'month') filename = `Bao_cao_don_thang_${exportMonth}`;
    if (exportType === 'year') filename = `Bao_cao_don_nam_${exportYear}`;

    alert(`Đang tải xuống báo cáo: ${filename}.xlsx`);
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(val);

  // --- List View Components ---

  const filteredOrders = useMemo(() => {
    return orders.filter(o => {
      const matchSearch = o.id.toLowerCase().includes(searchTerm.toLowerCase()) || o.customerName.toLowerCase().includes(searchTerm.toLowerCase()) || o.customerPhone?.includes(searchTerm);
      const matchStatus = statusFilter === 'all' || o.status === statusFilter;
      return matchSearch && matchStatus;
    });
  }, [orders, searchTerm, statusFilter]);

  const stats = useMemo(() => {
    return {
      total: orders.length,
      revenue: orders.reduce((acc, o) => acc + o.total, 0),
      pending: orders.filter(o => o.status === 'pending').length,
      shipping: orders.filter(o => o.status === 'shipping').length
    }
  }, [orders]);

  if (viewMode === 'list') {
    return (
      <div className="min-h-screen pb-10 animate-fade-in font-sans space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">Quản lý Đơn ngoài sàn</h2>
            <p className="text-sm text-slate-500 mt-1">Quản lý đơn hàng tạo thủ công, bán tại quầy hoặc qua tin nhắn.</p>
          </div>
          <button 
            onClick={() => setViewMode('create')}
            className="px-4 py-2.5 bg-indigo-600 text-white rounded-xl text-sm font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center gap-2 transform hover:-translate-y-0.5"
          >
            <PlusCircle size={18} /> Tạo đơn mới
          </button>
        </div>

        {/* Dashboard Stats */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
           <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
              <div className="p-3 bg-blue-50 text-blue-600 rounded-lg"><Package size={20}/></div>
              <div>
                 <div className="text-xs text-slate-500 font-bold uppercase">Tổng đơn hàng</div>
                 <div className="text-xl font-bold text-slate-800">{stats.total}</div>
              </div>
           </div>
           <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
              <div className="p-3 bg-green-50 text-green-600 rounded-lg"><DollarSign size={20}/></div>
              <div>
                 <div className="text-xs text-slate-500 font-bold uppercase">Doanh thu</div>
                 <div className="text-xl font-bold text-slate-800">{formatCurrency(stats.revenue)}</div>
              </div>
           </div>
           <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
              <div className="p-3 bg-yellow-50 text-yellow-600 rounded-lg"><Clock size={20}/></div>
              <div>
                 <div className="text-xs text-slate-500 font-bold uppercase">Chờ xử lý</div>
                 <div className="text-xl font-bold text-slate-800">{stats.pending}</div>
              </div>
           </div>
           <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
              <div className="p-3 bg-indigo-50 text-indigo-600 rounded-lg"><Truck size={20}/></div>
              <div>
                 <div className="text-xs text-slate-500 font-bold uppercase">Đang giao</div>
                 <div className="text-xl font-bold text-slate-800">{stats.shipping}</div>
              </div>
           </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
          {/* Toolbar */}
          <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex flex-col lg:flex-row gap-4 justify-between items-start lg:items-center">
             {/* Left: Filters */}
             <div className="flex flex-wrap gap-2 items-center w-full lg:w-auto">
                <div className="relative">
                   <input 
                     type="text" 
                     placeholder="Tìm mã đơn, khách hàng..." 
                     value={searchTerm}
                     onChange={(e) => setSearchTerm(e.target.value)}
                     className="pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 w-full sm:w-64"
                   />
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                </div>
                <select 
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                  className="px-3 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white"
                >
                   <option value="all">Tất cả trạng thái</option>
                   <option value="pending">Mới tạo</option>
                   <option value="processing">Đang xử lý</option>
                   <option value="shipping">Đang giao</option>
                   <option value="delivered">Hoàn thành</option>
                   <option value="cancelled">Đã hủy</option>
                </select>
             </div>

             {/* Right: Export */}
             <div className="flex flex-wrap gap-2 items-center bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                <span className="text-xs font-bold text-slate-500 px-2">Xuất báo cáo:</span>
                <select 
                  value={exportType} 
                  onChange={(e) => setExportType(e.target.value as any)}
                  className="text-sm border-none bg-transparent font-medium text-slate-700 focus:ring-0 cursor-pointer"
                >
                   <option value="date">Theo Ngày</option>
                   <option value="month">Theo Tháng</option>
                   <option value="year">Theo Năm</option>
                </select>

                <div className="w-px h-4 bg-slate-200 mx-1"></div>

                {exportType === 'date' && (
                   <input type="date" value={exportDate} onChange={(e) => setExportDate(e.target.value)} className="text-sm border-slate-200 rounded-md py-1 px-2 focus:ring-indigo-500" />
                )}
                {exportType === 'month' && (
                   <input type="month" value={exportMonth} onChange={(e) => setExportMonth(e.target.value)} className="text-sm border-slate-200 rounded-md py-1 px-2 focus:ring-indigo-500" />
                )}
                {exportType === 'year' && (
                   <select value={exportYear} onChange={(e) => setExportYear(Number(e.target.value))} className="text-sm border-slate-200 rounded-md py-1 px-2 focus:ring-indigo-500">
                      {[2024, 2025, 2026].map(y => <option key={y} value={y}>{y}</option>)}
                   </select>
                )}

                <button 
                  onClick={handleExport}
                  className="bg-green-600 text-white p-1.5 rounded hover:bg-green-700 transition-colors ml-2"
                  title="Tải xuống Excel"
                >
                   <Download size={16} />
                </button>
             </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-500 font-semibold border-b border-slate-200">
                <tr>
                  <th className="px-6 py-4">Mã đơn</th>
                  <th className="px-6 py-4">Khách hàng</th>
                  <th className="px-6 py-4">Sản phẩm</th>
                  <th className="px-6 py-4 text-center">Ngày tạo</th>
                  <th className="px-6 py-4 text-right">Tổng tiền</th>
                  <th className="px-6 py-4 text-center">Trạng thái</th>
                  <th className="px-6 py-4 text-right">Hành động</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredOrders.length === 0 ? (
                   <tr><td colSpan={7} className="text-center py-8 text-slate-400">Chưa có đơn hàng nào</td></tr>
                ) : (
                   filteredOrders.map(order => (
                    <tr key={order.id} className="hover:bg-slate-50 group">
                      <td className="px-6 py-4 font-mono font-medium text-indigo-600">{order.id}</td>
                      <td className="px-6 py-4">
                        <div className="font-bold text-slate-700">{order.customerName}</div>
                        <div className="text-xs text-slate-500">{order.customerPhone}</div>
                      </td>
                      <td className="px-6 py-4">
                         <div className="text-slate-700 truncate max-w-[200px]">{order.items[0]?.name}</div>
                         {order.items.length > 1 && <div className="text-xs text-slate-400">+{order.items.length - 1} sản phẩm khác</div>}
                      </td>
                      <td className="px-6 py-4 text-center text-slate-600">{order.date.split(' ')[1] || order.date}</td>
                      <td className="px-6 py-4 text-right font-bold text-slate-800">{formatCurrency(order.total)}</td>
                      <td className="px-6 py-4 text-center">
                        <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase border ${
                           order.status === 'delivered' ? 'bg-green-100 text-green-700 border-green-200' :
                           order.status === 'cancelled' ? 'bg-red-100 text-red-700 border-red-200' :
                           order.status === 'shipping' ? 'bg-blue-100 text-blue-700 border-blue-200' :
                           'bg-yellow-100 text-yellow-700 border-yellow-200'
                        }`}>
                           {order.status === 'pending' ? 'Mới tạo' : order.status === 'processing' ? 'Đang xử lý' : order.status === 'shipping' ? 'Đang giao' : order.status === 'delivered' ? 'Hoàn thành' : 'Đã hủy'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                         <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded" title="In đơn"><Printer size={16}/></button>
                            <button className="p-1.5 text-slate-400 hover:text-orange-600 hover:bg-orange-50 rounded" title="Chi tiết"><MoreHorizontal size={16}/></button>
                         </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          <div className="p-4 border-t border-slate-100 bg-slate-50 text-xs text-slate-500 flex justify-between items-center">
             <span>Hiển thị {filteredOrders.length} đơn hàng</span>
             <div className="flex gap-1">
                <button className="px-2 py-1 bg-white border rounded hover:bg-slate-100 disabled:opacity-50" disabled>Trước</button>
                <button className="px-2 py-1 bg-white border rounded hover:bg-slate-100 disabled:opacity-50" disabled>Sau</button>
             </div>
          </div>
        </div>
      </div>
    );
  }

  // --- Create Order View ---
  return (
    <div className="pb-10 animate-fade-in font-sans h-full flex flex-col">
      <div className="mb-6 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-3">
          <button onClick={() => setViewMode('list')} className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors">
             <ArrowLeft size={24} />
          </button>
          <div>
            <h2 className="text-2xl font-bold text-slate-800">Tạo Đơn Hàng Mới</h2>
            <p className="text-sm text-slate-500 mt-1">Nhập thông tin để tạo đơn thủ công.</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1 overflow-hidden">
        <div className="lg:col-span-2 space-y-6 overflow-y-auto pr-2 custom-scrollbar">
          {/* Stepper */}
          <div className="bg-white rounded-xl p-4 shadow-sm border border-slate-200 flex justify-between items-center relative">
             <div className="absolute top-1/2 left-10 right-10 h-0.5 bg-slate-100 -z-0"></div>
             {[1, 2, 3].map((step) => (
                <div key={step} className="relative z-10 flex flex-col items-center gap-2 cursor-pointer" onClick={() => setCurrentStep(step)}>
                   <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-all ${currentStep === step ? 'bg-indigo-600 text-white ring-4 ring-indigo-100' : currentStep > step ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-400'}`}>
                      {currentStep > step ? <CheckCircle size={16}/> : step}
                   </div>
                   <span className={`text-xs font-medium ${currentStep === step ? 'text-indigo-700' : 'text-slate-500'}`}>{step === 1 ? 'Khách hàng' : step === 2 ? 'Sản phẩm' : 'Vận chuyển'}</span>
                </div>
             ))}
          </div>

          {/* Steps Content */}
          <div className={`bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden transition-all duration-300 min-h-[400px]`}>
             <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                <h3 className="font-bold text-slate-800 flex items-center gap-2">
                   {currentStep === 1 ? <User size={18} className="text-indigo-600"/> : currentStep === 2 ? <Package size={18} className="text-indigo-600"/> : <Truck size={18} className="text-indigo-600"/>}
                   {currentStep === 1 ? 'Thông tin khách hàng' : currentStep === 2 ? 'Thông tin sản phẩm' : 'Vận chuyển'}
