             </div>

             <div className="p-6">
               {currentStep === 1 && (
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-fade-in">
                    <div className="md:col-span-2 relative">
                       <input type="text" placeholder="Tìm khách hàng cũ (SĐT/Tên)..." className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none" />
