                    </div>
                 </div>
               )}

               {currentStep === 2 && (
                 <div className="space-y-4 animate-fade-in">
                    <div className="relative">
                       <input 
                         type="text" 
                         value={productSearch}
                         onChange={(e) => { setProductSearch(e.target.value); setIsProductDropdownOpen(true); }}
                         className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none" 
                         placeholder="Tìm sản phẩm..."
                       />
                       <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                       {isProductDropdownOpen && productSearch && (
                          <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl max-h-60 overflow-y-auto z-20">
                             {MOCK_PRODUCTS.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase())).map(p => (
                                <div key={p.id} className="p-3 hover:bg-slate-50 cursor-pointer flex items-center gap-3 border-b border-slate-50" onClick={() => handleAddProduct(p)}>
