                                   <div className="flex-1 text-sm font-medium">{p.name}</div>
                                   <div className="text-sm font-bold text-indigo-600">{formatCurrency(p.price)}</div>
                                </div>
                             ))}
                          </div>
                       )}
                    </div>

                    {selectedProducts.map((item) => (
                       <div key={item.product.id} className="flex items-center gap-3 p-3 border border-slate-200 rounded-lg bg-slate-50">
                          <img src={item.product.image} className="w-12 h-12 rounded border border-slate-200 bg-white" />
                          <div className="flex-1 min-w-0">
                             <div className="text-sm font-medium truncate">{item.product.name}</div>
                             <div className="text-xs text-slate-500">{item.product.sku}</div>
