                          <div className="flex items-center border border-slate-200 rounded bg-white">
                             <button onClick={() => updateQuantity(item.product.id, -1)} className="px-2 py-1 hover:bg-slate-100 text-slate-600 font-bold">-</button>
                             <span className="px-2 text-sm font-medium w-8 text-center">{item.quantity}</span>
                             <button onClick={() => updateQuantity(item.product.id, 1)} className="px-2 py-1 hover:bg-slate-100 text-slate-600 font-bold">+</button>
                          </div>
                          <div className="text-sm font-bold text-slate-800 w-24 text-right">{formatCurrency(item.price * item.quantity)}</div>
                          <button onClick={() => { setSelectedProducts(prev => prev.filter(p => p.product.id !== item.product.id)) }} className="text-slate-400 hover:text-red-500 p-1"><Trash2 size={16}/></button>
                       </div>
                    ))}

                    {selectedProducts.length === 0 && <div className="text-center py-8 text-slate-400 text-sm">Chưa có sản phẩm nào được chọn</div>}

                    <div className="flex justify-between pt-4 border-t border-slate-100">
                        <button onClick={() => setCurrentStep(1)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50">Quay lại</button>
