                    </div>
                 </div>
               )}

               {currentStep === 3 && (
                 <div className="space-y-6 animate-fade-in">
                    <div className="grid grid-cols-4 gap-4">
                       <div><label className="text-xs text-slate-500">KL (g)</label><input type="number" value={packageInfo.weight} onChange={(e) => setPackageInfo({...packageInfo, weight: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg text-sm px-2 py-1.5"/></div>
                       <div><label className="text-xs text-slate-500">D (cm)</label><input type="number" value={packageInfo.length} onChange={(e) => setPackageInfo({...packageInfo, length: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg text-sm px-2 py-1.5"/></div>
                       <div><label className="text-xs text-slate-500">R (cm)</label><input type="number" value={packageInfo.width} onChange={(e) => setPackageInfo({...packageInfo, width: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg text-sm px-2 py-1.5"/></div>
                       <div><label className="text-xs text-slate-500">C (cm)</label><input type="number" value={packageInfo.height} onChange={(e) => setPackageInfo({...packageInfo, height: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg text-sm px-2 py-1.5"/></div>
                    </div>

                    <h4 className="text-sm font-bold text-slate-700 border-b border-slate-100 pb-2">Chọn đơn vị vận chuyển</h4>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                       {CARRIERS.map(carrier => (
                          <div key={carrier.id} onClick={() => { setSelectedCarrierId(carrier.id); setShippingFee(carrier.fee); }} className={`border rounded-lg p-3 cursor-pointer flex justify-between items-center transition-all ${selectedCarrierId === carrier.id ? 'border-indigo-600 bg-indigo-50 ring-1 ring-indigo-600' : 'border-slate-200 hover:border-indigo-300'}`}>
                             <div className="flex items-center gap-3">
                                <img src={carrier.logo} className="w-8 h-8 object-contain" />
                                <div><div className="font-bold text-sm text-slate-800">{carrier.name}</div><div className="text-xs text-slate-500">{carrier.timeStr}</div></div>
                             </div>
                             <div className="font-bold text-indigo-600">{formatCurrency(carrier.fee)}</div>
                          </div>
                       ))}
                    </div>

                    <div className="flex justify-between pt-4 border-t border-slate-100">
                        <button onClick={() => setCurrentStep(2)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50">Quay lại</button>
                    </div>
                 </div>
               )}
             </div>
          </div>
        </div>

        {/* Summary Card */}
        <div className="lg:col-span-1">
           <div className="bg-white rounded-xl shadow-lg border border-slate-200 p-6 sticky top-6">
              <h3 className="font-bold text-lg text-slate-800 mb-4 pb-4 border-b border-slate-100">Tổng quan đơn hàng</h3>
              <div className="space-y-3 text-sm mb-6">
                 <div className="flex justify-between text-slate-600"><span>Tiền hàng</span><span className="font-medium text-slate-800">{formatCurrency(subtotal)}</span></div>
                 <div className="flex justify-between text-slate-600"><span>Phí vận chuyển</span><span className="font-medium text-slate-800">{formatCurrency(shippingFee)}</span></div>
                 <div className="flex justify-between items-center text-slate-600">
                    <span>Giảm giá</span>
                    <div className="flex items-center gap-1 w-24 border-b border-slate-200"><input type="number" value={discountValue} onChange={(e) => setDiscountValue(Number(e.target.value))} className="w-full text-right text-red-500 font-medium bg-transparent outline-none"/><span className="text-xs text-slate-400 cursor-pointer" onClick={() => setDiscountType(prev => prev === 'percent' ? 'fixed' : 'percent')}>{discountType === 'percent' ? '%' : 'đ'}</span></div>
                 </div>
                 <div className="flex justify-between text-slate-600 items-center">
                    <span>Thu hộ (COD)</span>
                    <div className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" checked={isCodEnabled} onChange={(e) => setIsCodEnabled(e.target.checked)} className="sr-only peer" />
                        <div className="w-9 h-5 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-green-600"></div>
                    </div>
                 </div>

                 <div className="border-t border-dashed border-slate-200 pt-3 flex justify-between items-end"><span className="font-bold text-slate-800 text-base">Tổng thu</span><span className="font-extrabold text-indigo-600 text-2xl">{formatCurrency(totalAmount)}</span></div>
              </div>
              <button 
                onClick={handleCreateOrder} 
                disabled={currentStep !== 3 || !selectedCarrierId}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-lg shadow-sm transition-all flex items-center justify-center gap-2 disabled:bg-slate-300 disabled:cursor-not-allowed"
              >
                 <CreditCard size={18} /> Tạo đơn ngay
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default CreateOrder;

import React, { useState, useEffect, useMemo } from 'react';
import { MOCK_PRODUCTS, MOCK_ORDERS } from '../services/mockData';
import { Product, Order } from '../types';
import { 
  User, Phone, MapPin, Search, Trash2, Truck, 
  CreditCard, Package, CheckCircle, ChevronRight, UserPlus, PlusCircle,
  Box, Scale, History, DollarSign, Percent, ArrowLeft, Tag, Clock, Zap,
  FileSpreadsheet, Filter, Download, Calendar, MoreHorizontal, Printer, X,
  Edit3, Save
} from 'lucide-react';

const CARRIERS = [
  { id: 'ghtk', name: 'Giao Hàng Tiết Kiệm', logo: 'https://picsum.photos/50/50?random=ghtk', fee: 35000, time: 3, timeStr: '2-3 ngày' },
  { id: 'ghn', name: 'Giao Hàng Nhanh', logo: 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e3/Logo_GHN_Slogan_En.png/320px-Logo_GHN_Slogan_En.png', fee: 32000, time: 3, timeStr: '2-3 ngày' },
  { id: 'viettel', name: 'Viettel Post', logo: 'https://upload.wikimedia.org/wikipedia/commons/0/08/Viettel_Post_logo.png', fee: 28000, time: 4, timeStr: '3-4 ngày' },
];

const CreateOrder: React.FC = () => {
  const [viewMode, setViewMode] = useState<'list' | 'create' | 'edit'>('list');
  const [editingId, setEditingId] = useState<string | null>(null);

  // Create/Edit Order State
  const [currentStep, setCurrentStep] = useState(1);
  const [customer, setCustomer] = useState({ name: '', phone: '', address: '', city: '', district: '', note: '' });
  const [selectedProducts, setSelectedProducts] = useState<{product: Product, quantity: number, price: number}[]>([]);
  const [productSearch, setProductSearch] = useState('');
  const [isProductDropdownOpen, setIsProductDropdownOpen] = useState(false);
  const [packageInfo, setPackageInfo] = useState({ weight: 500, length: 10, width: 10, height: 5 });
  const [selectedCarrierId, setSelectedCarrierId] = useState<string>('');
  const [shippingFee, setShippingFee] = useState(0);
  const [isCodEnabled, setIsCodEnabled] = useState(true);
  const [discountValue, setDiscountValue] = useState(0);
  const [discountType, setDiscountType] = useState<'fixed' | 'percent'>('fixed');

  // List / Management State
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');

  // Date Range Filter State
  const [dateRange, setDateRange] = useState({ start: '', end: '' });

  // Export State
  const [exportType, setExportType] = useState<'date' | 'month' | 'year'>('month');
  const [exportDate, setExportDate] = useState(new Date().toISOString().split('T')[0]);
  const [exportMonth, setExportMonth] = useState(new Date().toISOString().slice(0, 7)); // YYYY-MM
  const [exportYear, setExportYear] = useState(new Date().getFullYear());

  // Print State
  const [printOrder, setPrintOrder] = useState<Order | null>(null);

  useEffect(() => {
    // Initialize with manual orders from mock + any local additions
    const manualOrders = MOCK_ORDERS.filter(o => o.platform === 'Manual');
    setOrders(manualOrders);
  }, []);

  const subtotal = selectedProducts.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const discountAmount = discountType === 'fixed' ? discountValue : (subtotal * discountValue) / 100;
  const totalAmount = Math.max(0, subtotal + shippingFee - discountAmount);

  // --- Handlers ---

  const handleAddProduct = (product: Product) => {
    setSelectedProducts(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { product, quantity: 1, price: product.price }];
    });
    setProductSearch('');
    setIsProductDropdownOpen(false);
  };

  const updateQuantity = (id: string, delta: number) => {
    setSelectedProducts(prev => prev.map(item => item.product.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item));
  };

  // Parse custom date string "HH:mm DD/MM/YY" or ISO to Date object
  const parseDate = (dateStr: string) => {
    try {
      if (dateStr.includes('T')) return new Date(dateStr); // ISO format
      const [time, date] = dateStr.split(' ');
      const [day, month, year] = date.split('/');
      return new Date(Number(`20${year}`), Number(month) - 1, Number(day));
    } catch (e) {
      return new Date();
    }
  };

  const resetForm = () => {
    setCustomer({ name: '', phone: '', address: '', city: '', district: '', note: '' });
    setSelectedProducts([]);
    setCurrentStep(1);
    setDiscountValue(0);
    setShippingFee(0);
    setSelectedCarrierId('');
    setEditingId(null);
  };

  const handleCreateOrder = () => {
    if (!customer.name || !customer.phone || selectedProducts.length === 0 || !selectedCarrierId) return alert("Vui lòng điền đầy đủ thông tin.");

    const newOrder: any = {
      id: editingId || `MAN-${Date.now().toString().slice(-6)}`,
      customerName: customer.name,
      customerPhone: customer.phone,
      address: customer.address,
      date: editingId ? (orders.find(o => o.id === editingId)?.date || new Date().toLocaleString('vi-VN')) : new Date().toLocaleString('vi-VN'),
      total: totalAmount,
      status: 'pending',
      items: selectedProducts.map(p => ({...p.product, quantity: p.quantity})),
      platform: 'Manual',
      shippingFee: shippingFee,
      isCOD: isCodEnabled,
      note: customer.note,
      shippingCarrier: selectedCarrierId
    };

    if (editingId) {
      setOrders(prev => prev.map(o => o.id === editingId ? newOrder : o));
      alert("Cập nhật đơn hàng thành công!");
    } else {
      setOrders([newOrder, ...orders]);
      alert("Tạo đơn hàng thành công!");
    }

    resetForm();
    setViewMode('list');
  };

  const handleEditOrder = (order: Order) => {
    setEditingId(order.id);
    setCustomer({
      name: order.customerName,
      phone: order.customerPhone || '',
      address: order.address || '',
      city: '', 
      district: '',
      note: order.note || ''
    });

    // Map order items back to selection
    const mappedItems = order.items.map(item => {
      // Find full product details from MOCK_PRODUCTS if possible, otherwise construct minimal
      const fullProduct = MOCK_PRODUCTS.find(p => p.id === item.productId) || {
        id: item.productId,
        name: item.name,
        sku: item.sku,
        price: item.price,
        image: item.image,
        // ... defaults
      } as Product;

      return {
        product: fullProduct,
        quantity: item.quantity,
        price: item.price
      };
    });
    setSelectedProducts(mappedItems);

    setShippingFee(order.shippingFee);
    // Find carrier based on logic or default
    const carrier = CARRIERS.find(c => c.name === order.shippingCarrier) || CARRIERS[0];
    setSelectedCarrierId(carrier.id);
    setIsCodEnabled(order.isCOD);

    setViewMode('edit');
    setCurrentStep(1);
  };

  const handleExport = () => {
    let filename = '';
    if (exportType === 'date') filename = `Bao_cao_don_ngay_${exportDate}`;
    if (exportType === 'month') filename = `Bao_cao_don_thang_${exportMonth}`;
    if (exportType === 'year') filename = `Bao_cao_don_nam_${exportYear}`;

    alert(`Đang tải xuống báo cáo: ${filename}.xlsx`);
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(val);

  // --- List View Components ---

  const filteredOrders = useMemo(() => {
    return orders.filter(o => {
      const matchSearch = o.id.toLowerCase().includes(searchTerm.toLowerCase()) || o.customerName.toLowerCase().includes(searchTerm.toLowerCase()) || o.customerPhone?.includes(searchTerm);
      const matchStatus = statusFilter === 'all' || o.status === statusFilter;

      let matchDate = true;
      if (dateRange.start || dateRange.end) {
        const orderDate = parseDate(o.date);
        // Reset time for comparison
        orderDate.setHours(0,0,0,0);

        if (dateRange.start) {
          const start = new Date(dateRange.start);
          start.setHours(0,0,0,0);
          if (orderDate < start) matchDate = false;
        }
        if (dateRange.end) {
          const end = new Date(dateRange.end);
          end.setHours(23,59,59,999);
          if (orderDate > end) matchDate = false;
        }
      }

      return matchSearch && matchStatus && matchDate;
    });
  }, [orders, searchTerm, statusFilter, dateRange]);

  const stats = useMemo(() => {
    return {
      total: orders.length,
      revenue: orders.reduce((acc, o) => acc + o.total, 0),
      pending: orders.filter(o => o.status === 'pending').length,
      shipping: orders.filter(o => o.status === 'shipping').length
    }
  }, [orders]);

  // --- Render Print Modal ---
  const renderPrintModal = () => {
    if (!printOrder) return null;
    return (
      <div className="fixed inset-0 z-50 bg-black/60 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden flex flex-col max-h-[90vh]">
          <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
            <h3 className="font-bold text-slate-800 flex items-center gap-2">
              <Printer size={18} /> In hóa đơn
            </h3>
            <button onClick={() => setPrintOrder(null)} className="text-slate-400 hover:text-slate-600"><X size={20}/></button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 bg-slate-100">
            {/* Receipt Preview */}
            <div className="bg-white p-6 shadow-sm mx-auto text-sm font-mono leading-relaxed" style={{ maxWidth: '300px' }}>
              <div className="text-center mb-4 border-b border-dashed border-slate-300 pb-4">
                <h2 className="font-bold text-lg text-slate-900">OMNISALES STORE</h2>
                <p className="text-slate-500 text-xs">123 Đường ABC, Quận 1, TP.HCM</p>
                <p className="text-slate-500 text-xs">Hotline: 1900 1234</p>
              </div>

              <div className="mb-4">
                <div className="flex justify-between"><span>Mã đơn:</span> <span className="font-bold">{printOrder.id}</span></div>
                <div className="flex justify-between"><span>Ngày:</span> <span>{printOrder.date.split(' ')[1]}</span></div>
                <div className="flex justify-between"><span>Khách:</span> <span>{printOrder.customerName}</span></div>
                <div className="flex justify-between"><span>SĐT:</span> <span>{printOrder.customerPhone}</span></div>
              </div>

              <div className="border-b border-dashed border-slate-300 pb-2 mb-2">
                <div className="flex font-bold mb-1">
                  <span className="flex-1">Mặt hàng</span>
                  <span className="w-8 text-center">SL</span>
                  <span className="w-16 text-right">Thành tiền</span>
                </div>
                {printOrder.items.map((item, idx) => (
                  <div key={idx} className="flex mb-1">
                    <span className="flex-1 truncate pr-1">{item.name}</span>
                    <span className="w-8 text-center">{item.quantity}</span>
