                    <div className="flex items-center gap-1 w-24 border-b border-slate-200"><input type="number" value={discountValue} onChange={(e) => setDiscountValue(Number(e.target.value))} className="w-full text-right text-red-500 font-medium bg-transparent outline-none"/><span className="text-xs text-slate-400 cursor-pointer" onClick={() => setDiscountType(prev => prev === 'percent' ? 'fixed' : 'percent')}>{discountType === 'percent' ? '%' : 'đ'}</span></div>
