                        <div className="w-9 h-5 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-green-600"></div>
                    </div>
                 </div>

                 <div className="border-t border-dashed border-slate-200 pt-3 flex justify-between items-end"><span className="font-bold text-slate-800 text-base">Tổng thu</span><span className="font-extrabold text-indigo-600 text-2xl">{formatCurrency(totalAmount)}</span></div>
              </div>
              <button 
                onClick={handleCreateOrder} 
                disabled={currentStep !== 3 || !selectedCarrierId}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-lg shadow-sm transition-all flex items-center justify-center gap-2 disabled:bg-slate-300 disabled:cursor-not-allowed"
              >
                 {viewMode === 'edit' ? <Save size={18} /> : <CreditCard size={18} />} 
                 {viewMode === 'edit' ? 'Cập nhật đơn' : 'Tạo đơn ngay'}
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

