              className="flex-1 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 shadow-sm flex items-center justify-center gap-2"
            >
              <Printer size={18} /> In ngay
            </button>
          </div>
        </div>
      </div>
    );
  };

