  // Handle ESC key to close search
  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setSearchQuery('');
        setSearchResults(null);
        searchInputRef.current?.blur();
      }
