                            <span className="text-slate-500">Phương thức:</span>
                            <span className={`font-bold ${order.shippingMethod === 'Hỏa tốc' ? 'text-red-600' : 'text-slate-700'}`}>
                               {order.shippingMethod || 'Tiêu chuẩn'}
